const q = $input.first().json.query != null ? String($input.first().json.query) : '';
return [{
  json: {
    queryIgnored: q,
    urls: {
      n8n: 'http://127.0.0.1:5678/',
      supabaseGateway: 'http://kong:8000/',
      ollama: 'http://ollama:11434/',
    },
    validateRpc: {
      jsonrpc: '2.0',
      id: 1,
      method: 'tools/call',
      params: { name: 'search_workflows', arguments: { limit: 200 } },
    },
  },
}];

function parseMcpSse(raw) {
  const text = typeof raw === 'string' ? raw : String(raw ?? '');
  const dataLine = text.split(/?
/).find((line) => line.startsWith('data: '));
  if (!dataLine) throw new Error('Invalid MCP search_workflows response: ' + text.slice(0, 400));
  const payload = JSON.parse(dataLine.slice(6));
  if (payload.error) throw new Error(payload.error.message || JSON.stringify(payload.error));
  const contentText = payload.result?.content?.[0]?.text;
  if (contentText) {
    try { return JSON.parse(contentText); } catch { return {}; }
  }
  return payload.result?.structuredContent || {};
}

const sse = $('MCP Validate').first().json;
const data = parseMcpSse(sse.body ?? sse.data ?? '');
const rows = Array.isArray(data.data) ? data.data : [];
const count = typeof data.count === 'number' ? data.count : rows.length;
const preview = rows.slice(0, 12).map((w) => ({
  id: w.id,
  name: w.name,
  active: w.active,
}));
return [{
  json: {
    ...$('Build SDK Payload').first().json,
    workflowCount: count,
    workflowsPreview: preview,
  },
}];

return await (async () => {
  const parse = $('Parse Validate').first().json;
  const kongHttp = $('MCP Create').first().json || {};
  const kongCode = kongHttp.statusCode ?? kongHttp.status ?? 0;
  let ollama = { reachable: false, modelCount: 0, models: [] };
  let oErr = '';
  try {
    if (typeof $helpers !== 'undefined' && $helpers.httpRequest) {
      const tags = await $helpers.httpRequest({
        method: 'GET',
        url: parse.urls.ollama + 'api/tags',
        json: true,
        timeout: 6000,
      });
      const names = Array.isArray(tags.models) ? tags.models.map((m) => m.name).slice(0, 40) : [];
      ollama = { reachable: true, modelCount: names.length, models: names };
    } else {
      oErr = 'Code helper $helpers.httpRequest not available in this n8n build';
    }
  } catch (e) {
    oErr = String(e.message || e);
  }
  const nextSteps = [
    'Browse n8n at ' + parse.urls.n8n,
    'Open Chat Hub → Workflow agents → AI Starter Console for a guided tour.',
    'Fetch the JSON catalog: GET http://localhost:5678/webhook/template-kit-index',
    'Call Template - Supabase API Health Check webhook for gateway auth probes.',
  ];
  return [{
    json: {
      kong: {
        probeUrl: parse.urls.supabaseGateway,
        statusCode: kongCode,
        ok: kongCode > 0 && kongCode < 500,
      },
      ollama,
      n8n: {
        workflowsVisible: parse.workflowCount,
        sample: parse.workflowsPreview,
      },
      urls: parse.urls,
      ollamaError: oErr,
      nextSteps,
      response: JSON.stringify({
        kongStatus: kongCode,
        workflowCount: parse.workflowCount,
        ollamaOk: ollama.reachable,
        models: ollama.models.slice(0, 6),
      }, null, 2),
    },
  }];
})();
